<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Receipt Management</title><style>body{margin:0;background:#f5f7fb;color:#1f2a37;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Arial,sans-serif}header{background:#153764;color:white;padding:18px 24px}.wrap{max-width:1240px;margin:0 auto;padding:22px 16px}.card{background:white;border:1px solid #d9dee8;border-radius:8px;padding:18px}.bar{display:grid;grid-template-columns:1.4fr repeat(5,1fr) auto;gap:10px;margin-bottom:14px}input,select{min-height:40px;border:1.5px solid #cbd3df;border-radius:6px;padding:8px 10px}.btn{border:0;border-radius:6px;padding:10px 14px;font-weight:900;text-decoration:none;display:inline-flex;background:#153764;color:white}.btn.light{background:white;color:#153764;border:1.5px solid #d9dee8}table{width:100%;border-collapse:collapse}th,td{text-align:left;padding:10px 8px;border-bottom:1px solid #edf0f5;font-size:13px;vertical-align:top}.status{padding:3px 8px;border-radius:999px;background:#eef3f9;color:#153764;font-weight:900;font-size:11px}.notice{background:#e8f6ef;color:#237a4f;padding:10px 12px;border-radius:8px;margin-bottom:12px}@media(max-width:1000px){.bar{grid-template-columns:1fr 1fr}table{display:block;overflow-x:auto}}</style></head><body><header><h1>Receipt / Fapiao Management</h1></header><main class="wrap">@if(session('status'))<div class="notice">{{ session('status') }}</div>@endif<div class="card"><form class="bar" method="GET"><input name="search" value="{{ request('search') }}" placeholder="Registration, buyer, email, receipt number"><select name="status"><option value="">Status</option>@foreach(['not_requested','requested','pending_issue','issued','sent','failed','cancelled','voided'] as $status)<option value="{{ $status }}" @selected(request('status')===$status)>{{ $status }}</option>@endforeach</select><select name="receipt_type"><option value="">Type</option>@foreach(['personal','company','donation','none'] as $type)<option value="{{ $type }}" @selected(request('receipt_type')===$type)>{{ $type }}</option>@endforeach</select><select name="period"><option value="">Period</option><option value="main">Main</option><option value="late">Late</option></select><select name="payment_status"><option value="">Payment</option><option value="paid">Paid</option><option value="waiting_verification">Waiting</option><option value="pending">Pending</option></select><input type="date" name="date_from" value="{{ request('date_from') }}"><button class="btn" type="submit">Filter</button></form><p><a class="btn light" href="{{ route('admin.receipts.export', request()->query()) }}">Export CSV</a> <a class="btn light" href="{{ route('admin.receipts.settings') }}">E-Invoice Settings</a></p><table><thead><tr><th>Registration</th><th>Student</th><th>Buyer</th><th>Type</th><th>Company / GUI</th><th>Email</th><th>Service Fee</th><th>Receipt Amount</th><th>Status</th><th>Receipt No.</th><th>Issued</th><th></th></tr></thead><tbody>@foreach($receipts as $receipt)<tr><td>{{ $receipt->registration?->registration_number }}</td><td>{{ $receipt->registration?->student_full_name }}</td><td>{{ $receipt->buyer_name }}</td><td>{{ $receipt->receipt_type }}</td><td>{{ $receipt->company_name }}<br>{{ $receipt->gui_tax_id }}</td><td>{{ $receipt->buyer_email }}<br>{{ $receipt->buyer_phone }}</td><td>{{ $receipt->currency }} {{ number_format($receipt->service_fee_amount) }}</td><td>{{ $receipt->currency }} {{ number_format($receipt->taxable_receipt_amount) }}</td><td><span class="status">{{ $receipt->status }}</span></td><td>{{ $receipt->receipt_number }}</td><td>{{ optional($receipt->issued_at)->format('Y-m-d') }}</td><td><a class="btn light" href="{{ route('admin.receipts.show',$receipt) }}">View</a></td></tr>@endforeach</tbody></table>{{ $receipts->links() }}</div></main></body></html>
